import React, { useEffect, useState } from "react";
import { useParams } from "react-router-dom";
import Navbar from "../components/Navbar";
import { getMatches, getMatchPlayers, joinMatch } from "../services/api";

function MatchDetail() {
  const { id } = useParams();
  const [match, setMatch] = useState(null);
  const [players, setPlayers] = useState([]);
  const [userId, setUserId] = useState(1);
  const [message, setMessage] = useState("");
  const [error, setError] = useState("");

  useEffect(() => {
    const fetchData = async () => {
      try {
        const allMatches = await getMatches();
        const foundMatch = allMatches.find((m) => String(m.id) === String(id));
        setMatch(foundMatch || null);

        const playerData = await getMatchPlayers(id);
        setPlayers(playerData);
      } catch (err) {
        setError(err.message);
      }
    };

    fetchData();
  }, [id]);

  const handleJoin = async () => {
    setMessage("");
    setError("");

    try {
      const result = await joinMatch({
        user_id: Number(userId),
        match_id: Number(id),
      });

      setMessage(result.message || "Tham gia trận thành công");

      const playerData = await getMatchPlayers(id);
      setPlayers(playerData);
    } catch (err) {
      setError(err.message);
    }
  };

  return (
    <div>
      <Navbar />

      <div className="container page-section">
        {error && <p className="error-text">{error}</p>}

        {match && (
          <div className="simple-card">
            <h1 className="section-title">{match.title}</h1>
            <p className="section-subtitle">
              Xem thông tin trận đấu và đăng ký tham gia.
            </p>

            <div style={{ display: "grid", gap: "12px", marginBottom: "24px" }}>
              <p className="field-info">
                <strong>Địa điểm:</strong> {match.location}
              </p>

              <p className="field-info">
                <strong>Thời gian:</strong> {match.time}
              </p>

              <p className="field-info">
                <strong>Số người tối đa:</strong> {match.max_players}
              </p>

              <p className="field-info">
                <strong>Số người đã tham gia:</strong> {players.length}
              </p>

              <p className="field-info">
                <strong>Số chỗ còn lại:</strong>{" "}
                {Number(match.max_players) - players.length}
              </p>
            </div>

            <div
              style={{
                background: "#fff7ed",
                border: "1px solid #fdba74",
                padding: "14px",
                borderRadius: "12px",
                marginBottom: "20px",
                color: "#9a3412",
                fontWeight: 600,
              }}
            >
              Lưu ý: Nếu đã đăng ký nhưng không đến, bạn sẽ bị trừ 10.000 VNĐ.
            </div>

            <div style={{ marginBottom: "24px" }}>
              <label style={{ display: "block", marginBottom: "8px", fontWeight: 600 }}>
                Mã người dùng
              </label>
              <input
                type="number"
                value={userId}
                onChange={(e) => setUserId(e.target.value)}
                style={{
                  width: "220px",
                  padding: "12px",
                  borderRadius: "10px",
                  border: "1px solid #cbd5e1",
                }}
              />
            </div>

            <button className="btn-primary" onClick={handleJoin}>
              Tham gia trận
            </button>

            {message && <p className="success-text">{message}</p>}
            {error && <p className="error-text">{error}</p>}

            <div style={{ marginTop: "30px" }}>
              <h2 style={{ marginBottom: "16px" }}>Danh sách người tham gia</h2>

              <div className="table-wrap">
                <table>
                  <thead>
                    <tr>
                      <th>Mã người dùng</th>
                      <th>Tên người dùng</th>
                    </tr>
                  </thead>
                  <tbody>
                    {players.map((player) => (
                      <tr key={player.id}>
                        <td>{player.id}</td>
                        <td>{player.username}</td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

export default MatchDetail;
